package com.evolua.notification.interfaces.rest; import com.evolua.notification.application.NotificationJobService; import com.evolua.notification.domain.NotificationJob; import com.evolua.notification.infrastructure.security.CurrentUserProvider; import io.swagger.v3.oas.annotations.Operation; import jakarta.validation.Valid; import jakarta.validation.constraints.NotBlank; import java.util.List; import org.springframework.http.HttpStatus; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/v1/notifications") public class NotificationJobController { private final NotificationJobService service; private final CurrentUserProvider currentUserProvider; public NotificationJobController(NotificationJobService service, CurrentUserProvider currentUserProvider) { this.service = service; this.currentUserProvider = currentUserProvider; } @PostMapping @Operation(summary = "Create notification") public ResponseEntity<ApiResponse<NotificationJob>> create(@Valid @RequestBody NotificationJobRequest request) { NotificationJob created = service.create(currentUserProvider.getCurrentUser().userId(), request.channel(), request.message()); return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success(201, "Created", created)); } @GetMapping @Operation(summary = "List notifications") public ResponseEntity<ApiResponse<List<NotificationJob>>> list() { return ResponseEntity.ok(ApiResponse.success(200, "Listed", service.list(currentUserProvider.getCurrentUser().userId()))); } public record NotificationJobRequest(@NotBlank String channel, @NotBlank String message) { } }
